import{_ as a,o as t,c as i,a2 as s}from"./chunks/framework.CHeM0PsO.js";const p=JSON.parse('{"title":"Local visual regression testing","description":"","frontmatter":{"rfc":"0059","title":"Local visual regression testing","status":"Draft","date":"July 2026","author":"kasunben","scope":"packages/ui, runtime, plugins/account, plugins/console, plugins/launcher, __tests__/visual, docs; builds on RFC 0010 and epic task 9.7","incorporated_into_plan":"Yes - epic task 9.14"},"headers":[],"relativePath":"rfcs/0059-local-visual-regression-testing.md","filePath":"rfcs/0059-local-visual-regression-testing.md"}'),o={name:"rfcs/0059-local-visual-regression-testing.md"};function r(n,e,l,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Add local, Playwright-based visual regression testing for Sovereign&#39;s stabilizing UI. The first tier uses Storybook as the fixture source for <code>packages/ui</code> components. A second, smaller tier captures runtime shell and first-party plugin smoke screens. Screenshot baselines are managed locally and in CI; no hosted visual review product is required.</p><p>This RFC also defines the snapshot-testing boundary: broad React DOM snapshots are discouraged for UI. Snapshot tests are reserved for stable serialized outputs where textual diffs are meaningful, such as generated registries, manifest validation, normalized email HTML/text, and config JSON.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Sovereign&#39;s UI is becoming a public contract. <code>@sovereignfs/ui</code> components, semantic tokens, shell layout, Account, Console, Launcher, overlays, and mobile navigation are now stable enough that accidental visual changes should be caught before review.</p><p>The project should still preserve its self-hosted and local-first posture. A hosted visual review tool such as Chromatic or Percy would improve review UX, but it introduces an external service and project-level process before the local need is proven. Playwright screenshots provide the necessary regression signal with the tooling Sovereign already uses for e2e.</p><h2 id="current-state" tabindex="-1">Current state <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current state&quot;">​</a></h2><ul><li>RFC 0010 reserves visual test naming and layout conventions but does not choose visual regression tooling.</li><li>Storybook is planned/used as the component reference surface for <code>packages/ui</code> in epic task 9.7.</li><li>Existing e2e tests use Playwright for browser-driven golden paths.</li><li><code>docs/testing-e2e.md</code> documents Playwright usage but does not cover visual baselines.</li><li>There is no hosted visual review tool, no committed screenshot baseline set, and no policy for when snapshots are appropriate.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="tooling" tabindex="-1">Tooling <a class="header-anchor" href="#tooling" aria-label="Permalink to &quot;Tooling&quot;">​</a></h3><p>Use Playwright screenshots for visual regression.</p><p>The initial scripts should be local and CI-friendly:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:visual</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:visual:update</span></span></code></pre></div><p><code>test:visual</code> runs screenshot comparisons. <code>test:visual:update</code> refreshes baselines intentionally. CI should fail on visual diffs and upload screenshot diff artifacts where the existing CI environment supports artifacts.</p><p>No Chromatic, Percy, Loki, or other hosted visual review system is required. Those can be reconsidered later if local baseline review becomes too slow or high-friction.</p><h3 id="tier-1-storybook-component-visuals" tabindex="-1">Tier 1: Storybook component visuals <a class="header-anchor" href="#tier-1-storybook-component-visuals" aria-label="Permalink to &quot;Tier 1: Storybook component visuals&quot;">​</a></h3><p><code>packages/ui</code> is the canonical first target because it is a public UI contract for platform screens and plugin developers.</p><p>Run Playwright against the built Storybook output and capture stable component states:</p><ul><li>light and dark themes;</li><li>mobile, tablet, and desktop viewports where component behavior changes;</li><li>default, disabled, loading, error, selected, and empty states;</li><li>overlay/open states for <code>Dialog</code>, <code>Drawer</code>, <code>Popover</code>, and similar components;</li><li>token gallery and component gallery smoke screenshots.</li></ul><p>Baselines for this tier may be committed because the set is curated and stable. Avoid screenshots for every permutation if the result becomes noisy. The suite should protect meaningful contracts, not record every possible prop combination.</p><h3 id="tier-2-runtime-shell-and-first-party-plugin-visuals" tabindex="-1">Tier 2: runtime shell and first-party plugin visuals <a class="header-anchor" href="#tier-2-runtime-shell-and-first-party-plugin-visuals" aria-label="Permalink to &quot;Tier 2: runtime shell and first-party plugin visuals&quot;">​</a></h3><p>Add a small Playwright visual smoke suite for integrated app surfaces:</p><ul><li>auth login screen;</li><li>Launcher plugin grid;</li><li>Account profile/security/preferences;</li><li>Console settings/system health;</li><li>overlay route presentation;</li><li>mobile nav drawer and mobile header/footer layout;</li><li>instance identity / attribution surfaces when configured.</li></ul><p>This tier must stay intentionally small. Its purpose is to catch layout regressions across the composed runtime, not to screenshot every workflow. Behavior and data correctness remain the job of unit, integration, and e2e tests.</p><h3 id="baseline-policy" tabindex="-1">Baseline policy <a class="header-anchor" href="#baseline-policy" aria-label="Permalink to &quot;Baseline policy&quot;">​</a></h3><p>Screenshot baselines are source artifacts. Updating them is an intentional review act, not a side effect of running tests.</p><p>Rules:</p><ul><li>commit baselines only for curated, stable screenshots;</li><li>keep dynamic data, timestamps, random IDs, and animation out of screenshots;</li><li>prefer seeded deterministic fixtures;</li><li>use fixed viewport sizes and fonts in CI;</li><li>disable or reduce motion during visual tests;</li><li>mask unavoidable dynamic regions rather than accepting noisy diffs;</li><li>use <code>test:visual:update</code> only when the visual change is expected.</li></ul><p>CI should upload actual/expected/diff images when a visual test fails. The project does not need a hosted visual dashboard for the first implementation.</p><h3 id="snapshot-policy" tabindex="-1">Snapshot policy <a class="header-anchor" href="#snapshot-policy" aria-label="Permalink to &quot;Snapshot policy&quot;">​</a></h3><p>Do not use broad UI DOM snapshots such as <code>expect(container).toMatchSnapshot()</code> for components or pages. They are noisy, review poorly, and rarely catch the visual regressions users notice.</p><p>Allowed snapshot use cases:</p><ul><li>generated plugin registry output;</li><li>manifest/schema validation output;</li><li>normalized email HTML and plain text;</li><li>stable config JSON;</li><li>CLI output when normalized for paths, versions, and timestamps.</li></ul><p>Prefer semantic assertions for UI behavior:</p><ul><li>labels are connected to controls;</li><li>dialogs and menus open/close;</li><li>active navigation is announced correctly;</li><li>form errors are associated with fields;</li><li>keyboard navigation and focus management work.</li></ul><p>Visual screenshots complement these semantic assertions; they do not replace them.</p><h3 id="test-placement" tabindex="-1">Test placement <a class="header-anchor" href="#test-placement" aria-label="Permalink to &quot;Test placement&quot;">​</a></h3><p>Follow RFC 0010&#39;s boundary rule:</p><ul><li>Storybook/component visual tests live with <code>packages/ui</code> or under its visual test folder.</li><li>Cross-runtime visual smoke tests live under root <code>__tests__/visual/</code>.</li><li>Filenames use <code>*.visual.spec.ts</code> or the convention chosen by the Playwright config.</li></ul><p>The exact folder layout can be finalized during implementation, but the boundary rule remains: package-owned visuals stay with the package; composed app visuals live at the root.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><h3 id="chromatic" tabindex="-1">Chromatic <a class="header-anchor" href="#chromatic" aria-label="Permalink to &quot;Chromatic&quot;">​</a></h3><p>Excellent Storybook visual review UX, but it introduces a hosted dependency, account management, and potentially paid/private-project constraints. Deferred until local Playwright review proves insufficient.</p><h3 id="percy" tabindex="-1">Percy <a class="header-anchor" href="#percy" aria-label="Permalink to &quot;Percy&quot;">​</a></h3><p>Good Playwright integration for app-flow screenshots, but it has the same hosted dependency tradeoff as Chromatic and is less directly tied to the component Storybook surface. Deferred.</p><h3 id="loki" tabindex="-1">Loki <a class="header-anchor" href="#loki" aria-label="Permalink to &quot;Loki&quot;">​</a></h3><p>Purpose-built for Storybook screenshot testing and can run locally, but it adds another toolchain when Playwright is already present for e2e. Rejected for the first implementation.</p><h3 id="broad-react-snapshots" tabindex="-1">Broad React snapshots <a class="header-anchor" href="#broad-react-snapshots" aria-label="Permalink to &quot;Broad React snapshots&quot;">​</a></h3><p>Rejected for UI. They create high-churn text artifacts that reviewers often approve mechanically. Use semantic assertions and visual screenshots instead.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li>Exact baseline directory layout for Storybook versus root visual tests.</li><li>Whether baselines should be committed immediately or introduced first as CI artifacts during a calibration period.</li><li>Per-platform tolerance policy: Linux-only CI baselines versus local macOS baselines.</li><li>Whether <code>test:visual</code> should run in the default verification gate or remain a targeted check until the baseline set stabilizes.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li>Add Playwright visual config and scripts: <code>test:visual</code> and <code>test:visual:update</code>.</li><li>Build Storybook before component visual tests and capture a small curated baseline set for <code>packages/ui</code>.</li><li>Add root <code>__tests__/visual/</code> smoke specs for auth, shell, Launcher, Account, Console, overlays, and mobile navigation.</li><li>Document baseline update workflow in <code>docs/testing-e2e.md</code> or a dedicated visual-testing doc.</li><li>Add CI artifact upload for visual diffs.</li><li>Revisit hosted visual review only if local workflow becomes a bottleneck.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>July 2026</td><td>Initial draft</td></tr></tbody></table>`,55)])])}const m=a(o,[["render",r]]);export{p as __pageData,m as default};
